import streamlit as st


def render_action_plan_styles():
    st.markdown(
        """
        <style>
        .action-module{border-radius:28px;padding:26px;margin-top:18px;border:1px solid rgba(226,232,240,.95);box-shadow:0 18px 48px rgba(15,23,42,.06)}
        .action-kicker{display:inline-flex;width:fit-content;padding:7px 12px;border-radius:999px;background:rgba(255,255,255,.72);border:1px solid rgba(15,23,42,.08);font-size:12px;font-weight:900;color:#334155;margin-bottom:12px;letter-spacing:.04em}
        .action-module h3{font-size:30px;line-height:1.2;letter-spacing:-.04em;color:#0f172a;margin:0 0 10px}.action-module h4{color:#0f172a}.action-lead{font-size:15px;color:#475569;line-height:1.85;max-width:920px;margin:0 0 20px}.action-module p{color:#475569;line-height:1.75}
        .ldp-module{background:radial-gradient(circle at top left,#dbeafe,transparent 35%),linear-gradient(135deg,#ffffff,#eff6ff)}.pixel-module{background:radial-gradient(circle at top right,#dcfce7,transparent 34%),linear-gradient(135deg,#ffffff,#f0fdf4)}.ga4-module{background:radial-gradient(circle at top left,#ede9fe,transparent 34%),linear-gradient(135deg,#ffffff,#faf5ff)}.dropoff-module{background:radial-gradient(circle at top right,#fef3c7,transparent 34%),linear-gradient(135deg,#ffffff,#fffbeb)}.case-module{background:radial-gradient(circle at top left,#fce7f3,transparent 34%),linear-gradient(135deg,#ffffff,#fdf2f8)}.stability-module{background:radial-gradient(circle at top right,#dcfce7,transparent 34%),radial-gradient(circle at bottom left,#dbeafe,transparent 32%),linear-gradient(135deg,#ffffff,#f8fafc)}
        .action-flow-row{display:grid;grid-template-columns:1fr 44px 1fr 44px 1fr;gap:10px;align-items:stretch;margin:20px 0}.action-flow-card{border-radius:20px;background:rgba(255,255,255,.78);border:1px solid #dbeafe;padding:18px;min-height:110px;box-shadow:0 12px 30px rgba(15,23,42,.05)}.action-flow-card b{display:block;color:#0f172a;font-size:17px;margin-bottom:5px}.action-flow-card span{font-size:13px;color:#475569;line-height:1.55}.action-flow-arrow,.dropoff-arrow{display:flex;align-items:center;justify-content:center;color:#94a3b8;font-size:28px;font-weight:950}
        .action-grid-2{display:grid;grid-template-columns:repeat(2,minmax(0,1fr));gap:14px;margin-top:18px}.action-mini-card{border-radius:20px;background:rgba(255,255,255,.78);border:1px solid #bbf7d0;padding:18px;min-height:120px;box-shadow:0 12px 30px rgba(15,23,42,.05)}.action-mini-card b{color:#14532d;font-size:17px}.action-mini-card span{display:block;color:#475569;font-size:13px;line-height:1.65;margin-top:6px}
        .action-list{list-style:none;padding:0;margin:18px 0 0;display:grid;grid-template-columns:repeat(2,minmax(0,1fr));gap:12px}.action-list li{background:rgba(255,255,255,.78);border:1px solid #ddd6fe;border-radius:18px;padding:14px 16px;color:#475569;box-shadow:0 10px 26px rgba(15,23,42,.045)}.action-list li:before{content:'✓';display:inline-flex;align-items:center;justify-content:center;width:22px;height:22px;border-radius:999px;background:#ede9fe;color:#6d28d9;font-weight:950;margin-right:8px}
        .dropoff-flow{display:grid;grid-template-columns:1fr 38px 1fr 38px 1.2fr 38px 1.2fr;gap:10px;align-items:stretch;margin-top:20px}.dropoff-node{border-radius:20px;background:rgba(255,255,255,.78);border:1px solid #fde68a;padding:18px;color:#78350f;font-weight:850;display:flex;align-items:center;justify-content:center;text-align:center;min-height:115px;box-shadow:0 12px 30px rgba(15,23,42,.05)}
        .timeline-card{display:grid;gap:12px;margin-top:20px}.timeline-card div{position:relative;border-radius:18px;background:rgba(255,255,255,.78);border:1px solid #fbcfe8;padding:15px 18px 15px 42px;color:#475569;box-shadow:0 10px 26px rgba(15,23,42,.045)}.timeline-card div:before{content:'';position:absolute;left:17px;top:20px;width:10px;height:10px;border-radius:999px;background:#ec4899;box-shadow:0 0 0 5px #fce7f3}.timeline-card b{color:#831843}
        .stability-grid{display:grid;grid-template-columns:repeat(4,minmax(0,1fr));gap:12px;margin:20px 0}.stability-box{background:rgba(255,255,255,.8);border:1px solid #bbf7d0;border-radius:18px;padding:16px;min-height:90px;display:flex;align-items:center;justify-content:center;text-align:center;color:#14532d;font-weight:850;box-shadow:0 12px 30px rgba(15,23,42,.05)}.handover-card{background:linear-gradient(135deg,#ffffff,#eff6ff);border:1px solid #bfdbfe;border-radius:22px;padding:20px;margin-top:16px;box-shadow:0 14px 34px rgba(15,23,42,.06)}.handover-card h4{font-size:20px;margin:0 0 8px;color:#0f172a}.handover-card p{font-size:14px;color:#475569;line-height:1.8;margin:0}
        @media(max-width:900px){.action-flow-row,.dropoff-flow,.action-grid-2,.action-list,.stability-grid{grid-template-columns:1fr}.action-flow-arrow,.dropoff-arrow{min-height:24px;transform:rotate(90deg)}}
        </style>
        """,
        unsafe_allow_html=True,
    )
